#!/usr/bin/env python3
"""Apply start-state patches to the workspace."""
from pathlib import Path

WORK = Path('/work')

# Patch: scrapy/downloadermiddlewares/robotstxt.py
_content_scrapy_downloadermiddlewares_robotstxt_py = '"""\nThis is a middleware to respect robots.txt policies. To activate it you must\nenable this middleware and enable the ROBOTSTXT_OBEY setting.\n\n"""\n\nimport logging\n\nfrom twisted.internet.defer import Deferred, maybeDeferred\n\nfrom scrapy.exceptions import IgnoreRequest, NotConfigured\nfrom scrapy.http import Request\nfrom scrapy.http.request import NO_CALLBACK\nfrom scrapy.utils.httpobj import urlparse_cached\nfrom scrapy.utils.log import failure_to_exc_info\nfrom scrapy.utils.misc import load_object\n\nlogger = logging.getLogger(__name__)\n\n\nclass RobotsTxtMiddleware:\n    DOWNLOAD_PRIORITY = 1000\n\n    def __init__(self, crawler):\n        if not crawler.settings.getbool("ROBOTSTXT_OBEY"):\n            raise NotConfigured\n        self._default_useragent = crawler.settings.get("USER_AGENT", "Scrapy")\n        self._robotstxt_useragent = crawler.settings.get("ROBOTSTXT_USER_AGENT", None)\n        self.crawler = crawler\n        self._parsers = {}\n        self._parserimpl = load_object(crawler.settings.get("ROBOTSTXT_PARSER"))\n\n        # check if parser dependencies are met, this should throw an error otherwise.\n        self._parserimpl.from_crawler(self.crawler, b"")\n\n    @classmethod\n    def from_crawler(cls, crawler):\n        return cls(crawler)\n\n    def process_request(self, request, spider):\n        if request.meta.get("dont_obey_robotstxt"):\n            return\n        if request.url.startswith("data:") or request.url.startswith("file:"):\n            return\n        d = maybeDeferred(self.robot_parser, request, spider)\n        d.addCallback(self.process_request_2, request, spider)\n        return d\n\n    def process_request_2(self, rp, request, spider):\n        if rp is None:\n            return\n\n        useragent = self._robotstxt_useragent\n        if not useragent:\n            useragent = request.headers.get(b"User-Agent", self._default_useragent)\n        if rp.allowed(request.url, useragent):  # BUG: logic inverted, blocks allowed URLs\n            logger.debug(\n                "Forbidden by robots.txt: %(request)s",\n                {"request": request},\n                extra={"spider": spider},\n            )\n            self.crawler.stats.inc_value("robotstxt/forbidden")\n            raise IgnoreRequest("Forbidden by robots.txt")\n\n    def robot_parser(self, request, spider):\n        url = urlparse_cached(request)\n        netloc = url.netloc\n\n        if netloc not in self._parsers:\n            self._parsers[netloc] = Deferred()\n            robotsurl = f"{url.scheme}://{url.netloc}/robots.txt"\n            robotsreq = Request(\n                robotsurl,\n                priority=self.DOWNLOAD_PRIORITY,\n                meta={"dont_obey_robotstxt": True},\n                callback=NO_CALLBACK,\n            )\n            dfd = self.crawler.engine.download(robotsreq)\n            dfd.addCallback(self._parse_robots, netloc, spider)\n            dfd.addErrback(self._logerror, robotsreq, spider)\n            dfd.addErrback(self._robots_error, netloc)\n            self.crawler.stats.inc_value("robotstxt/request_count")\n\n        if isinstance(self._parsers[netloc], Deferred):\n            d = Deferred()\n\n            def cb(result):\n                d.callback(result)\n                return result\n\n            self._parsers[netloc].addCallback(cb)\n            return d\n        return self._parsers[netloc]\n\n    def _logerror(self, failure, request, spider):\n        if failure.type is not IgnoreRequest:\n            logger.error(\n                "Error downloading %(request)s: %(f_exception)s",\n                {"request": request, "f_exception": failure.value},\n                exc_info=failure_to_exc_info(failure),\n                extra={"spider": spider},\n            )\n        return failure\n\n    def _parse_robots(self, response, netloc, spider):\n        self.crawler.stats.inc_value("robotstxt/response_count")\n        self.crawler.stats.inc_value(\n            f"robotstxt/response_status_count/{response.status}"\n        )\n        rp = self._parserimpl.from_crawler(self.crawler, response.body)\n        rp_dfd = self._parsers[netloc]\n        self._parsers[netloc] = rp\n        rp_dfd.callback(rp)\n\n    def _robots_error(self, failure, netloc):\n        if failure.type is not IgnoreRequest:\n            key = f"robotstxt/exception_count/{failure.type}"\n            self.crawler.stats.inc_value(key)\n        rp_dfd = self._parsers[netloc]\n        self._parsers[netloc] = None\n        rp_dfd.callback(None)\n'
(WORK / 'scrapy/downloadermiddlewares/robotstxt.py').write_text(_content_scrapy_downloadermiddlewares_robotstxt_py)

print('Setup complete: patches applied.')
